import{_ as t,o as a,c as r,ag as o}from"./chunks/framework.f-eIl1f0.js";const m=JSON.parse('{"title":"Inspirations","description":"","frontmatter":{},"headers":[],"relativePath":"guide/comparisons.md","filePath":"guide/comparisons.md"}'),i={name:"guide/comparisons.md"};function s(n,e,l,c,p,d){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="inspirations" tabindex="-1">Inspirations <a class="header-anchor" href="#inspirations" aria-label="Permalink to &quot;Inspirations&quot;">​</a></h1><p>swatch learned from theme systems across many languages and platforms. Textual is Python, Lipgloss is Go, M3 is for mobile/web -- these aren&#39;t competitors but teachers. Each solved a piece of the theming puzzle, and swatch synthesizes the best ideas into a TypeScript-native, terminal-first, platform-agnostic package.</p><h2 id="textual" tabindex="-1">Textual <a class="header-anchor" href="#textual" aria-label="Permalink to &quot;Textual&quot;">​</a></h2><p><a href="https://textual.textualize.io/guide/design/" target="_blank" rel="noreferrer">Textual</a> is a Python TUI framework with an integrated CSS-based theme system. The single biggest influence on swatch.</p><p>Adopted: minimal authoring path (<code>Theme(primary=...)</code> -&gt; full theme), automatic shade generation (we use OKLCH instead of RGB), semantic token categories (<code>$primary</code>, <code>$surface</code>, <code>$error</code>). Diverged: Textual doesn&#39;t detect terminal colors (assumes full truecolor control), uses a CSS engine (we use framework-agnostic <code>$token</code> strings), and lacks the 16 ANSI accent spectrum.</p><p><strong>What we learned</strong>: One color in, full theme out. The minimal authoring path is essential.</p><h2 id="charm-lipgloss-bubbletea" tabindex="-1">Charm / Lipgloss + BubbleTea <a class="header-anchor" href="#charm-lipgloss-bubbletea" aria-label="Permalink to &quot;Charm / Lipgloss + BubbleTea&quot;">​</a></h2><p><a href="https://github.com/charmbracelet/lipgloss" target="_blank" rel="noreferrer">Lipgloss</a> is a Go styling library for terminal apps. <a href="https://github.com/lrstanley/bubbletint" target="_blank" rel="noreferrer">BubbleTint</a> adds theme registry support.</p><p>Adopted: color manipulation utilities as first-class API (<code>blend()</code>, <code>brighten()</code>, <code>darken()</code>, <code>contrastFg()</code>). The <code>CompleteAdaptiveColor</code> pattern (dark/light x truecolor/256/16) validates our ANSI 16 fallback approach. Using ANSI palette indices as &quot;semantic slots&quot; inspired our terminal color detection.</p><p><strong>What we learned</strong>: Color utilities should be first-class API. The ANSI palette as &quot;semantic slots&quot; is a powerful idea.</p><h2 id="catppuccin" tabindex="-1">Catppuccin <a class="header-anchor" href="#catppuccin" aria-label="Permalink to &quot;Catppuccin&quot;">​</a></h2><p><a href="https://catppuccin.com/" target="_blank" rel="noreferrer">Catppuccin</a> is a community-driven color scheme with 26 named colors and ports for 300+ apps.</p><p>Adopted: OKLCH bright variant formula for perceptually correct derivation. The 4 built-in Catppuccin palettes are among swatch&#39;s most popular presets. Diverged: 26 colors and 300+ manual per-app ports -- swatch&#39;s <code>deriveTheme()</code> eliminates manual porting.</p><p><strong>What we learned</strong>: OKLCH for derivation. Community-loved palettes are worth shipping built-in.</p><h2 id="base16-tinted-theming" tabindex="-1">Base16 / tinted-theming <a class="header-anchor" href="#base16-tinted-theming" aria-label="Permalink to &quot;Base16 / tinted-theming&quot;">​</a></h2><p><a href="https://github.com/tinted-theming/home" target="_blank" rel="noreferrer">Base16</a> defines 16-color themes with a template system for generating app configs.</p><p>Adopted: <code>importBase16()</code>/<code>exportBase16()</code> bridges the 230+ scheme ecosystem. The 16-slot palette maps directly to terminal ANSI colors. Diverged: Base16 uses opaque slot names (<code>base08</code> = &quot;usually red&quot;) -- swatch uses semantic names. Base16 is build-time only; swatch has a full runtime API.</p><p><strong>What we learned</strong>: The 16-slot palette is the universal terminal baseline.</p><h2 id="material-design-3" tabindex="-1">Material Design 3 <a class="header-anchor" href="#material-design-3" aria-label="Permalink to &quot;Material Design 3&quot;">​</a></h2><p><a href="https://m3.material.io/styles/color/system/how-the-system-works" target="_blank" rel="noreferrer">M3</a> uses HCT (Hue-Chroma-Tone) color science to derive themes from a single seed color.</p><p>Adopted: perceptually uniform color spaces (HCT/OKLCH) for derivation. The <code>onPrimary</code> concept (contrast text for colored backgrounds) maps to our <code>$primaryfg</code>/<code>$selectionfg</code> pattern. Rejected: secondary/tertiary accent families -- over-engineered for TUIs.</p><p><strong>What we learned</strong>: Perceptual color science produces better derivation than RGB/HSL.</p><h2 id="omarchy-dhh" tabindex="-1">Omarchy (DHH) <a class="header-anchor" href="#omarchy-dhh" aria-label="Permalink to &quot;Omarchy (DHH)&quot;">​</a></h2><p><a href="https://github.com/basecamp/omarchy" target="_blank" rel="noreferrer">Omarchy</a> -- one <code>colors.toml</code> generates configs for Neovim, tmux, bat, lazygit.</p><p>Adopted: the &quot;one source, many configs&quot; philosophy. Our ColorPalette -&gt; <code>deriveTheme()</code> is the same idea. Diverged: Omarchy requires all 22 values hand-specified with no derivation; swatch generates from minimal input.</p><p><strong>What we learned</strong>: Cross-tool config generation from a single palette is a high-value future direction.</p><h2 id="apple-hig" tabindex="-1">Apple HIG <a class="header-anchor" href="#apple-hig" aria-label="Permalink to &quot;Apple HIG&quot;">​</a></h2><p><a href="https://developer.apple.com/design/human-interface-guidelines/color" target="_blank" rel="noreferrer">Apple&#39;s HIG</a> -- system-wide color principles.</p><p>Adopted: text hierarchy via opacity cascade (primary -&gt; muted -&gt; disabled). ONE user-chosen accent color prevents the &quot;rainbow problem.&quot;</p><p><strong>What we learned</strong>: Text hierarchy via opacity. ONE accent color produces clean, focused UIs.</p><h2 id="oh-my-pi" tabindex="-1">oh-my-pi <a class="header-anchor" href="#oh-my-pi" aria-label="Permalink to &quot;oh-my-pi&quot;">​</a></h2><p><a href="https://github.com/can1357/oh-my-pi" target="_blank" rel="noreferrer">oh-my-pi</a> -- terminal AI coding agent with a 66-token, 3-layer theme system.</p><p>Adopted: the two-layer indirection pattern (raw palette -&gt; semantic tokens) validates our architecture. Color-blind mode with symbol differentiation is a genuine accessibility innovation. Rejected: 66 component-specific tokens (e.g., <code>breadcrumb_active_fg</code>) -- couples theme interface to UI implementation details.</p><p><strong>What we learned</strong>: Two-layer indirection is the core architectural insight. Keep tokens UI-agnostic.</p><h2 id="zed-editor" tabindex="-1">Zed Editor <a class="header-anchor" href="#zed-editor" aria-label="Permalink to &quot;Zed Editor&quot;">​</a></h2><p><a href="https://zed.dev/" target="_blank" rel="noreferrer">Zed</a> uses 150+ theme tokens with per-state variants (hover/active/disabled per token).</p><p>Rejected: too granular for TUIs -- <code>input_border_active_hover</code> belongs in CSS, not a theme interface. TUI components have fewer states than a desktop editor.</p><p><strong>What we learned</strong>: The right abstraction level depends on the platform. 49 tokens (33 semantic + 16 palette) is right for terminal/web; 150+ is right for a desktop editor.</p>',38)])])}const u=t(i,[["render",s]]);export{m as __pageData,u as default};
